    "TPR1_06": ["आगे क्या होगा? □, □□, □□□, ?", "प्रत्येक चरण पर वर्ग गिनें।", ["□□□□", "□□", "□□□□□", "□□□"], "प्रत्येक चरण में एक वर्ग जोड़ा जाता है: 1, 2, 3, इसलिए 4 वर्ग आते हैं।"],
    "TPR1_07": ["आगे क्या होगा? जेड, वाई, एक्स, डब्ल्यू, ?", "वर्णमाला पीछे की ओर जाती है.", ["वी", "यू", "एक्स", "टी"], "अक्षर वर्णमाला में पीछे की ओर जाते हैं: Z, Y, X, W, V।"],
    "TPR1_08": ["आगे क्या होगा? 10, 20, 30, 40, ?", "प्रत्येक संख्या समान चरण से बढ़ती है।", ["50", "45", "60", "55"], "चरण 10 से 10 तक हैं। 40 के बाद, अगला पद 50 है।"],
    "TPR1_09": ["आगे क्या होगा? 3, 6, 9, 12, ?", "प्रत्येक संख्या समान चरण से बढ़ती है।", ["15", "14", "18", "13"], "चरण 3 बटा 3 हैं। 12 के बाद, 3 का अगला गुणज 15 है।"],
